module fsm (
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

    parameter S0 = 3'b000, S1 = 3'b001, S2 = 3'b010, S3 = 3'b011, S4 = 3'b100, S5 = 3'b101, S6 = 3'b110, S7 = 3'b111;

    reg [2:0] current_state, next_state;

    always @(posedge CLK or posedge RST) begin
        if (RST) begin
            current_state <= S0;
            MATCH <= 1'b0;
        end
        else begin
            current_state <= next_state;
        end
    end

    always @(*) begin
        case (current_state)
            S0: begin
                if (IN) begin
                    next_state = S1;
                    MATCH = 1'b0;
                end
                else begin
                    next_state = S0;
                    MATCH = 1'b0;
                end
            end
            S1: begin
                if (IN) begin
                    next_state = S1;
                    MATCH = 1'b0;
                end
                else begin
                    next_state = S2;
                    MATCH = 1'b0;
                end
            end
            S2: begin
                if (IN) begin
                    next_state = S3;
                    MATCH = 1'b0;
                end
                else begin
                    next_state = S0;
                    MATCH = 1'b0;
                end
            end
            S3: begin
                if (IN) begin
                    next_state = S4;
                    MATCH = 1'b0;
                end
                else begin
                    next_state = S2;
                    MATCH = 1'b0;
                end
            end
            S4: begin
                if (IN) begin
                    next_state = S1;
                    MATCH = 1'b1; 
                end
                else begin
                    next_state = S2;
                    MATCH = 1'b0;
                end
            end
            default: begin
                    next_state = S0;
                    MATCH = 1'b0;
            end
    endcase
end // Auto-repaired
endmodule
